import 'dart:convert'; import 'package:injectable/injectable.dart'; import 'package:shared_preferences/shared_preferences.dart'; @singleton class CacheManager { final SharedPreferences _prefs; static const _prefix = 'cache_'; CacheManager(this._prefs); Future<void> put(String key, Map<String, dynamic> data, {Duration ttl = const Duration(minutes: 5)}) => _prefs.setString('$_prefix$key', jsonEncode({'data': data, 'exp': DateTime.now().add(ttl).millisecondsSinceEpoch})); Map<String, dynamic>? get(String key) { final r = _prefs.getString('$_prefix$key'); if (r == null) return null; final j = jsonDecode(r); if (DateTime.now().millisecondsSinceEpoch > j['exp']) { _prefs.remove('$_prefix$key'); return null; } return j['data']; } Future<void> invalidate(String key) => _prefs.remove('$_prefix$key'); Future<void> invalidateAll() async { final keys = _prefs.getKeys().where((k) => k.startsWith(_prefix)).toList(); for (final k in keys) await _prefs.remove(k); } }